// Build the brand-safe review-request email per matched booking.
// Copy/voice mirrors docs/n8n/review-request-email.md (approved, brand-safe).
const INSTALLERS = {
  aaron: { name: 'Aaron Groshong', phone: '(612) 406-7117' },
  noah:  { name: 'Noah Kreis',     phone: '(920) 860-7050' },
  cody:  { name: 'Cody Star',      phone: '(605) 214-1335' },
};
const FALLBACK = INSTALLERS.aaron;
const REVIEW_URL = 'REPLACE_WITH_GOOGLE_REVIEW_LINK'; // <-- paste your GBP write-a-review link
const FIND_TUNE_URL = 'https://tunedyota.com/find-your-exact-tune?utm_source=email&utm_medium=review-request&utm_campaign=referral';
const esc = (s) => String(s == null ? '' : s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');

function build(f, inst) {
  const first = (f.Name || 'there').split(' ')[0];
  const vehicle = f.Vehicle || 'Toyota';
  const city = f.City || 'your area';
  const subject = `How's your ${vehicle} driving, ${first}?`;
  const text =
    `Hi ${first},\n\n` +
    `It's been a little while since ${inst.name} dialed in your ${vehicle} at our ${city} ` +
    `event — we hope it's been a different truck to drive ever since. Sharper throttle, ` +
    `smoother shifts, and the right gear when you actually want it.\n\n` +
    `If it's living up to that, would you take two minutes to share it? A quick Google ` +
    `review is the single biggest way you can help other Toyota and Lexus owners find ` +
    `honest, in-person tuning — and it genuinely means a lot to a small crew like ours.\n\n` +
    `Leave a Google review: ${REVIEW_URL}\n\n` +
    `Know someone whose Toyota or Lexus deserves the same? Send them our way — they can ` +
    `find their exact tune and the next event near them in under two minutes:\n${FIND_TUNE_URL}\n\n` +
    `And if anything isn't driving the way you expected, just reply to this email or call ` +
    `${inst.name} at ${inst.phone} — we'd rather hear from you and make it right.\n\n` +
    `Thanks for trusting us with your build.\n\n— Tuned Yota · Undeniable Performance\n`;
  const btn = (href, label, bg, color) =>
    `<a href="${esc(href)}" style="display:inline-block;background:${bg};color:${color};font-weight:700;text-decoration:none;padding:13px 26px;border-radius:999px;font-size:15px;margin:6px 0">${esc(label)}</a>`;
  const html =
    `<div style="font-family:Arial,sans-serif;color:#3A2E26;max-width:560px;line-height:1.5">` +
    `<h2 style="color:#5B4B42">How's it driving, ${esc(first)}?</h2>` +
    `<p>It's been a little while since <strong>${esc(inst.name)}</strong> dialed in your <strong>${esc(vehicle)}</strong> at our <strong>${esc(city)}</strong> event — we hope it's been a different truck to drive ever since. Sharper throttle, smoother shifts, and the right gear when you actually want it.</p>` +
    `<p>If it's living up to that, would you take two minutes to share it? A quick Google review is the single biggest way you can help other Toyota and Lexus owners find honest, in-person tuning — and it genuinely means a lot to a small crew like ours.</p>` +
    `<p>${btn(REVIEW_URL, 'Leave a Google review →', '#B3D0D9', '#23303a')}</p>` +
    `<p>Know someone whose Toyota or Lexus deserves the same? Send them our way — they can find their exact tune and the next event near them in under two minutes.</p>` +
    `<p>${btn(FIND_TUNE_URL, 'Find Your Exact Tune →', '#5B4B42', '#ffffff')}</p>` +
    `<p>And if anything isn't driving the way you expected, just reply to this email or call <strong>${esc(inst.name)}</strong> at <strong>${esc(inst.phone)}</strong> — we'd rather hear from you and make it right.</p>` +
    `<p>Thanks for trusting us with your build.</p>` +
    `<p style="color:#7c8472;font-weight:700;letter-spacing:.04em">— Tuned Yota · Undeniable Performance</p>` +
    `</div>`;
  return { subject, html, text };
}

const out = [];
for (const item of $input.all()) {
  const f = item.json.fields || item.json;
  const recordId = item.json.id || (item.json.fields && item.json.id);
  if (!f.Email) continue;
  const inst = INSTALLERS[f.Installer] || FALLBACK;
  const email = build(f, inst);
  out.push({ json: { recordId, to: f.Email, subject: email.subject, html: email.html, text: email.text } });
}
return out;
